    private void jButton2ActionPerformed(java.awt.event.ActionEvent evt) {

        // Read registration form values.
        String email = jTextField1.getText();
        String password = String.valueOf(jPasswordField1.getPassword());

        // Validate required fields before any database call.
        if (email.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Veuillez saisir un email.");
            return;
        }

        if (password.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Veuillez saisir un mot de passe.");
            return;
        }

        try {
            Connection conn = DataSource.createConnection();

            // Check if the email already exists.
            String checkSql = "SELECT * FROM user WHERE email=?";
            PreparedStatement checkStmt = conn.prepareStatement(checkSql);
            checkStmt.setString(1, email);

            ResultSet rs = checkStmt.executeQuery();

            if (rs.next()) {
                // Stop registration when email is already used.
                JOptionPane.showMessageDialog(this, "Cet email existe déjà !");
                conn.close();
                return;
            }

            conn.close();

            // Create user account through User helper method.
            boolean success = User.addUser(email, password);

            if (success) {
                JOptionPane.showMessageDialog(this, "Compte créé avec succès !");
            } else {
                JOptionPane.showMessageDialog(this, "Erreur lors de la création du compte.");
            }

        } catch (Exception ex) {
            ex.printStackTrace();
            JOptionPane.showMessageDialog(this, "Erreur lors de la connexion à la base !");
        }

    }


    private void jButton1ActionPerformed(java.awt.event.ActionEvent evt) {

        // Read login credentials from form.
        String email = jTextField1.getText();
        String password = String.valueOf(jPasswordField1.getPassword());

        // Basic validation before querying database.
        if (email.isEmpty() || password.isEmpty()) {
            JOptionPane.showMessageDialog(this, "Please fill in all the fields.");
            return;
        }

        try {
            // Open connection through shared DataSource class.
            Connection conn = DataSource.createConnection();

            String sql = "SELECT id, email, password, statut FROM user WHERE email=? AND password=?";
            PreparedStatement stmt = conn.prepareStatement(sql);

            stmt.setString(1, email);
            stmt.setString(2, password);

            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {

                // Build authenticated user object from query result.
                User utilisateur = new User(
                        rs.getInt("id"),
                        rs.getString("email"),
                        rs.getString("password"),
                        rs.getString("statut")
                );

                    // Store logged-in user in memory.
                User.setCurrentUser(utilisateur);

                JOptionPane.showMessageDialog(this, "Connection successful !");

                    // Redirect to screen based on user role.
                String statut = utilisateur.getStatut();

                if (statut.equalsIgnoreCase("employe")) {
                    new employemenu().setVisible(true);
                }
                else  {
                    new customermenu().setVisible(true);
                }

                // Close login frame after successful navigation.
                this.dispose();

            } else {
                JOptionPane.showMessageDialog(this, "Email or password incorrect !");
            }

            conn.close();

        } catch (Exception ex) {
            ex.printStackTrace();
            JOptionPane.showMessageDialog(this, "error while connection !");
        }

    }

